// tools/wallet.js — Burner Wallet tools (BAT-582 Phase 4).
//
// Two tools:
//   - wallet_status     (read-only, no confirmation)
//   - wallet_set_caps   (confirm — diff message generated by confirmation/policy.js)
//
// All cap math is BigInt against atomic-unit strings. Decimals only enter
// at user-facing surfaces (decimal in args.per_tx_sol, decimal display in
// wallet_status output). Internal storage + bridge writes are atomic.

'use strict';

const { log } = require('../config');
const { androidBridgeCall } = require('../bridge');
const { getWallet } = require('../wallet');

const SOL_DECIMALS = 9;
const USDC_DECIMALS = 6;

// ── Decimal/atomic helpers (local — kept BigInt-pure, no Number math) ───────

// BAT-582 R10: bound model-controlled cap-decimal input BEFORE the regex
// + BigInt() pipeline. `wallet_set_caps` args are model-controlled (the
// agent calls this tool to set per-tx and daily caps). A pathological
// 10MB digit payload would burn O(n²) CPU before cap state mutates.
// 40 chars covers any realistic SOL/USDC cap (1 trillion SOL is 22
// lamport digits at 9 decimals) while rejecting DoS attempts.
const _MAX_DECIMAL_INPUT_LEN = 40;

function _decimalToAtomic(decimal, decimals) {
    if (decimal == null) return null;
    const s = String(decimal).trim();
    if (s.length === 0 || s.length > _MAX_DECIMAL_INPUT_LEN) return null;
    if (!/^[0-9]+(\.[0-9]+)?$/.test(s)) return null;
    const [intPart, fracPart = ''] = s.split('.');
    if (fracPart.length > decimals) return null;
    const padded = fracPart.padEnd(decimals, '0');
    const full = (intPart + padded).replace(/^0+/, '') || '0';
    try { return BigInt(full).toString(); } catch (_) { return null; }
}

function _atomicToDecimal(atomic, decimals) {
    if (atomic == null) return '0';
    let s;
    try { s = BigInt(String(atomic)).toString(); } catch (_) { return String(atomic); }
    if (s === '0') return '0';
    const pad = s.padStart(decimals + 1, '0');
    const head = pad.slice(0, pad.length - decimals);
    const tail = pad.slice(pad.length - decimals).replace(/0+$/, '');
    return tail.length ? `${head}.${tail}` : head;
}

// remaining = max(cap - spent, 0)
function _remaining(capAtomic, spentAtomic) {
    let cap;
    let spent;
    try {
        cap = BigInt(String(capAtomic || '0'));
        spent = BigInt(String(spentAtomic || '0'));
    } catch (_) { return '0'; }
    const r = cap - spent;
    return (r > 0n ? r : 0n).toString();
}

// ── Tool definitions ────────────────────────────────────────────────────────

const tools = [
    {
        name: 'wallet_status',
        description:
            "Read both wallets' state. Returns the burner wallet (if configured) and the " +
            'main wallet (MWA-backed; pubkey null until user authorizes). Network is Solana mainnet. ' +
            'Burner shape: { pubkey, balance: { sol, usdc }, balanceAvailable, spentToday: { sol, usdc }, ' +
            'caps: { perTxSol, perTxUsdc, dailySol, dailyUsdc }, remainingDaily: { sol, usdc }, display: {...}, network }. ' +
            'BALANCE NOTE: `burner.balance.sol` and `burner.balance.usdc` are currently always `null` ' +
            '(and `display.balanceSol` / `display.balanceUsdc` are the literal string "unavailable") — ' +
            'the burner balance RPC fetch is a known follow-up, not wired yet. `balanceAvailable: false` ' +
            'flags this. Caps, today\'s spend, and remainingDaily ARE real (atomic-unit strings; matching ' +
            'decimals appear under display.*). Main wallet `balance` is fetched live from RPC and IS real. ' +
            'When asked about the burner balance, say "burner balance is temporarily unavailable" or fetch ' +
            'the main wallet via solana_balance — never read burner.balance.* and report it as "0". ' +
            'Use this before deciding burner-vs-main routing or when the user asks "what wallets do I have." ' +
            'Read-only — no confirmation needed.',
        input_schema: {
            type: 'object',
            properties: {},
        },
    },
    {
        name: 'wallet_set_caps',
        description:
            'Update burner wallet spending caps (per-tx and daily, SOL and USDC). All four cap fields are ' +
            'optional — pass only the ones you want to change. Args are DECIMAL strings (e.g. "0.05" SOL = ' +
            '50000000 lamports internally), not atomic units; the tool converts decimals → atomic before ' +
            'writing. Returns { ok: true, applied: { capPerTxSol?, capPerTxUsdc?, capDailySol?, capDailyUsdc? } } ' +
            'with values as atomic-unit strings on success, or { error: <code>, reason: <message> } on failure. ' +
            'Stable error codes: "missing_fields" (no cap fields provided), "invalid_decimal" (one or more cap ' +
            'values failed decimal parsing — sign, exponent, or > field-decimals fractional digits), ' +
            '"bridge_failure" (the underlying /config/burner-caps bridge call returned an error or was unreachable). ' +
            'Each call REQUIRES user confirmation; the confirmation card shows an old → new diff ' +
            'auto-generated by the policy hook. Use sparingly — caps protect against runaway spend and ' +
            'prompt-injection abuse. Refuses cleanly if no burner is configured.',
        input_schema: {
            type: 'object',
            properties: {
                per_tx_sol:   { type: 'string', description: 'Per-transaction SOL cap (decimal, e.g. "0.05")' },
                daily_sol:    { type: 'string', description: 'Daily SOL cap (decimal, e.g. "0.20")' },
                per_tx_usdc:  { type: 'string', description: 'Per-transaction USDC cap (decimal, e.g. "5")' },
                daily_usdc:   { type: 'string', description: 'Daily USDC cap (decimal, e.g. "20")' },
            },
        },
    },
];

// ── Handlers ────────────────────────────────────────────────────────────────

const handlers = {
    /**
     * wallet_status — pure read. Reads /burner/status, plus main wallet
     * pubkey + balance from existing helpers. Output schema documented in
     * BAT-582 Phase 4 spec.
     *
     * BAT-582 R2: balance fields surface as null + a "balance unavailable"
     * display string until the RPC fetch is wired (the previous "0"-stub
     * was misleading: a configured-but-funded burner read like an empty
     * one). Caps and spend totals are still real numbers — they live in
     * Android-local state and don't need an RPC fetch.
     */
    async wallet_status(_input, _chatId) {
        // 1) Burner — read /burner/status directly so we can include cap fields.
        let burnerOut = null;
        try {
            const status = await androidBridgeCall('/burner/status', {}, 5000);
            if (status && !status.error && status.configured) {
                const capPerTxSol  = String(status.capPerTxSol  || '0');
                const capDailySol  = String(status.capDailySol  || '0');
                const capPerTxUsdc = String(status.capPerTxUsdc || '0');
                const capDailyUsdc = String(status.capDailyUsdc || '0');
                const spentTodaySol  = String(status.spentTodaySol  || '0');
                const spentTodayUsdc = String(status.spentTodayUsdc || '0');
                // BAT-582 R2: /burner/status no longer emits balanceSol /
                // balanceUsdc until the RPC fetch lands. Use null to mark
                // "unavailable" rather than fabricating "0" — the agent
                // and UI both check for null and surface the right copy.
                const hasSolBalance  = (status.balanceSol  != null);
                const hasUsdcBalance = (status.balanceUsdc != null);
                burnerOut = {
                    pubkey: status.pubkey || null,
                    balance: {
                        sol:  hasSolBalance  ? String(status.balanceSol)  : null,
                        usdc: hasUsdcBalance ? String(status.balanceUsdc) : null,
                    },
                    balanceAvailable: (hasSolBalance && hasUsdcBalance),
                    spentToday: {
                        sol:  spentTodaySol,
                        usdc: spentTodayUsdc,
                    },
                    caps: {
                        perTxSol:  capPerTxSol,
                        perTxUsdc: capPerTxUsdc,
                        dailySol:  capDailySol,
                        dailyUsdc: capDailyUsdc,
                    },
                    remainingDaily: {
                        sol:  _remaining(capDailySol,  spentTodaySol),
                        usdc: _remaining(capDailyUsdc, spentTodayUsdc),
                    },
                    // Decimal display for human-friendly chat surfaces.
                    display: {
                        balanceSol:    hasSolBalance  ? _atomicToDecimal(status.balanceSol,  SOL_DECIMALS) : 'unavailable',
                        balanceUsdc:   hasUsdcBalance ? _atomicToDecimal(status.balanceUsdc, USDC_DECIMALS) : 'unavailable',
                        capPerTxSol:   _atomicToDecimal(capPerTxSol,  SOL_DECIMALS),
                        capDailySol:   _atomicToDecimal(capDailySol,  SOL_DECIMALS),
                        capPerTxUsdc:  _atomicToDecimal(capPerTxUsdc, USDC_DECIMALS),
                        capDailyUsdc:  _atomicToDecimal(capDailyUsdc, USDC_DECIMALS),
                        spentTodaySol:  _atomicToDecimal(spentTodaySol,  SOL_DECIMALS),
                        spentTodayUsdc: _atomicToDecimal(spentTodayUsdc, USDC_DECIMALS),
                    },
                    network: status.network || 'mainnet',
                };
            }
        } catch (e) {
            log(`[wallet_status] burner status read failed: ${e.message}`, 'WARN');
        }

        // 2) Main — pubkey + balance via the existing solana.js helpers
        //    (lazy-loaded inside MainWallet to keep this code path testable).
        // BAT-582 R27: MainWallet.balance() now returns null on RPC
        // failure (parallel to burner). null → "unavailable" downstream
        // so a transient outage doesn't look like an empty wallet.
        const main = getWallet('main');
        let mainPubkey = null;
        let mainBalance = { sol: null, usdc: null };
        try { mainPubkey = await main.pubkey(); } catch (_) { mainPubkey = null; }
        try { mainBalance = await main.balance(); } catch (_) { mainBalance = { sol: null, usdc: null }; }

        // BAT-582 R27: render "unavailable" for main wallet balance when
        // the underlying RPC fetch failed (null sentinel). Matches the
        // burner-side handling above so agent + UI behave consistently.
        const mainHasSol  = (mainBalance.sol  != null);
        const mainHasUsdc = (mainBalance.usdc != null);
        return {
            burner: burnerOut,
            main: {
                pubkey: mainPubkey,
                balance: mainBalance,
                balanceAvailable: (mainHasSol && mainHasUsdc),
                role: 'main',
                signsViaPopup: true,
                display: {
                    balanceSol:  mainHasSol  ? _atomicToDecimal(mainBalance.sol,  SOL_DECIMALS)  : 'unavailable',
                    balanceUsdc: mainHasUsdc ? _atomicToDecimal(mainBalance.usdc, USDC_DECIMALS) : 'unavailable',
                },
            },
            network: 'mainnet',
        };
    },

    /**
     * wallet_set_caps — confirmable. Confirmation message comes from
     * getConfirmationPolicy; this handler trusts that ai.js has already
     * gated by the time it runs.
     *
     * Args are decimal strings; we convert to atomic before calling
     * /config/burner-caps. Reject malformed input clearly so the agent
     * can correct.
     */
    async wallet_set_caps(input, _chatId) {
        const a = input || {};
        const body = {};
        const errors = [];

        const ROWS = [
            ['per_tx_sol',  'capPerTxSol',  SOL_DECIMALS],
            ['daily_sol',   'capDailySol',  SOL_DECIMALS],
            ['per_tx_usdc', 'capPerTxUsdc', USDC_DECIMALS],
            ['daily_usdc',  'capDailyUsdc', USDC_DECIMALS],
        ];
        let provided = 0;
        for (const [argKey, capKey, decimals] of ROWS) {
            if (a[argKey] == null) continue;
            provided++;
            const atomic = _decimalToAtomic(a[argKey], decimals);
            if (atomic == null) {
                errors.push(`${argKey}: invalid decimal "${a[argKey]}" (no signs/exponents; max ${decimals} fractional digits)`);
            } else {
                body[capKey] = atomic;
            }
        }

        // BAT-582 R9: stable error codes. Failure shape is always
        // { error: <code>, reason: <message> } so the agent (and tests) can
        // pattern-match on the code without parsing the message string.
        // Codes: "missing_fields" | "invalid_decimal" | "bridge_failure".
        if (provided === 0) {
            return {
                error: 'missing_fields',
                reason: 'No cap fields provided. Pass at least one of per_tx_sol, daily_sol, per_tx_usdc, daily_usdc.',
            };
        }
        if (errors.length) {
            return {
                error: 'invalid_decimal',
                reason: `Invalid cap value(s): ${errors.join('; ')}`,
            };
        }

        const res = await androidBridgeCall('/config/burner-caps', body, 5000);
        if (!res || res.error) {
            // Bridge layer error — surface the upstream message verbatim
            // under `reason` while normalizing the code.
            const upstreamMsg = (res && res.reason) ? res.reason
                : (res && res.error) ? res.error
                : 'bridge_unreachable';
            return {
                error: 'bridge_failure',
                reason: upstreamMsg,
            };
        }
        return { ok: true, applied: body };
    },
};

module.exports = { tools, handlers, _decimalToAtomic, _atomicToDecimal };
